const rawOutput = $json.output || "";
let result = {
  isValid: false,
  errorMessage: "",
  action: "unknown",
  data: {}
};

// --- Nombres conocidos de campos de inicio y fin ---
const INICIO_KEYS = ["inicio", "start", "startdate", "fecha_inicio", "fecha", "date", "from", "begin"];
const FIN_KEYS    = ["fin", "end", "enddate", "fecha_fin", "final", "to", "until"];

// --- Busca recursivamente en cualquier nivel del JSON ---
function deepFind(obj, keys) {
  if (!obj || typeof obj !== "object") return null;
  for (const key of Object.keys(obj)) {
    if (keys.includes(key.toLowerCase())) {
      const val = obj[key];
      if (val && typeof val === "string") return val;
    }
  }
  for (const key of Object.keys(obj)) {
    const val = obj[key];
    if (val && typeof val === "object" && !Array.isArray(val)) {
      const found = deepFind(val, keys);
      if (found) return found;
    }
  }
  return null;
}

// --- Resuelve lenguaje natural + todos los formatos de fecha ---
function resolveNaturalDate(rawDate) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const lower = (rawDate || "").toLowerCase().trim();
  if (!lower) return today;

  if (lower.includes("hoy")) return today;

  if (lower.includes("pasado mañana")) {
    const d = new Date(today); d.setDate(d.getDate() + 2); return d;
  }
  if (lower.includes("mañana")) {
    const d = new Date(today); d.setDate(d.getDate() + 1); return d;
  }

  const daysMatch = lower.match(/(\d+)\s*d[íi]as?/);
  if (daysMatch) { const d = new Date(today); d.setDate(d.getDate() + parseInt(daysMatch[1])); return d; }

  const weeksMatch = lower.match(/(\d+)\s*semanas?/);
  if (weeksMatch) { const d = new Date(today); d.setDate(d.getDate() + parseInt(weeksMatch[1]) * 7); return d; }

  const monthsMatch = lower.match(/(\d+)\s*mes(es)?/);
  if (monthsMatch) { const d = new Date(today); d.setMonth(d.getMonth() + parseInt(monthsMatch[1])); return d; }

  // "5 de agosto de 2026"
  const meses = { enero:0,febrero:1,marzo:2,abril:3,mayo:4,junio:5,julio:6,agosto:7,septiembre:8,octubre:9,noviembre:10,diciembre:11 };
  const espMatch = lower.match(/(\d{1,2})\s+de\s+([a-záéíóú]+)\s+de\s+(\d{4})/);
  if (espMatch && meses[espMatch[2]] !== undefined) {
    return new Date(parseInt(espMatch[3]), meses[espMatch[2]], parseInt(espMatch[1]));
  }

  // dd/mm/yyyy
  const dmyMatch = lower.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (dmyMatch) return new Date(`${dmyMatch[3]}-${dmyMatch[2].padStart(2,'0')}-${dmyMatch[1].padStart(2,'0')}T00:00:00`);

  // yyyy-mm-dd
  const isoMatch = lower.match(/\d{4}-\d{2}-\d{2}/);
  if (isoMatch) return new Date(`${isoMatch[0]}T00:00:00`);

  return today;
}

// --- Date → ISO 8601 con Z ---
function toISO(date) {
  const pad = n => String(n).padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())}Z`;
}

try {
  const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error("No JSON found");

  const parsed = JSON.parse(jsonMatch[0]);
  result.action = (parsed.action || "unknown").toLowerCase();

  // --- CREATE ---
  if (result.action === "create") {
    const rawInicio = deepFind(parsed, INICIO_KEYS) || "";
    const rawFin    = deepFind(parsed, FIN_KEYS)    || "";

    const inicioDate = resolveNaturalDate(rawInicio);
    const finalDate  = rawFin ? resolveNaturalDate(rawFin) : new Date(inicioDate);

    // Hora inicio
    const horaInicio = parsed.hora_inicio || parsed.hora || "";
    const horaMatch  = horaInicio.match(/(\d{1,2}):(\d{2})/);
    if (horaMatch) {
      inicioDate.setHours(parseInt(horaMatch[1]), parseInt(horaMatch[2]), 0, 0);
    } else {
      inicioDate.setHours(0, 0, 0, 0);
    }

    // Hora final
    const horaFinal    = parsed.hora_final || parsed.hora_fin || "";
    const horaFinMatch = horaFinal.match(/(\d{1,2}):(\d{2})/);
    if (horaFinMatch) {
      finalDate.setHours(parseInt(horaFinMatch[1]), parseInt(horaFinMatch[2]), 0, 0);
    } else if (horaMatch) {
      // Hay hora inicio pero no fin → +1 hora por defecto
      finalDate.setHours(parseInt(horaMatch[1]) + 1, parseInt(horaMatch[2]), 0, 0);
    } else {
      finalDate.setHours(23, 59, 59, 0);
    }

    result.data = {
      action: "create",
      evento: typeof parsed.evento === "string" ? parsed.evento : (parsed.summary || parsed.title || parsed.destination || ""),
      inicio: toISO(inicioDate),
      final:  toISO(finalDate)
    };
    result.isValid = true;
  }

  // --- LIST ---
  else if (result.action === "list") {
    const rawDate = parsed.date || parsed.fecha || parsed.query || "";
    const dateMatch = rawDate.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
    result.data = {
      action: "list",
      searchDate: dateMatch
        ? `${dateMatch[3]}-${dateMatch[2].padStart(2,'0')}-${dateMatch[1].padStart(2,'0')}`
        : new Date().toISOString().split('T')[0]
    };
    result.isValid = true;
  }

  // --- OTRAS ACCIONES ---
  else {
    result.data = parsed;
    result.isValid = true;
  }

} catch (error) {
  result.isValid = false;
  result.errorMessage = "Error: " + error.message;
}

return result;
